import{_ as e,o as t,c as r,ag as o}from"./chunks/framework.B9unkguw.js";const m=JSON.parse('{"title":"매개변수","description":"","frontmatter":{},"headers":[],"relativePath":"ko/qgc-user-guide/setup_view/parameters.md","filePath":"ko/qgc-user-guide/setup_view/parameters.md"}'),s={name:"ko/qgc-user-guide/setup_view/parameters.md"};function i(n,a,p,l,c,d){return t(),r("div",null,a[0]||(a[0]=[o('<h1 id="매개변수" tabindex="-1">매개변수 <a class="header-anchor" href="#매개변수" aria-label="Permalink to &quot;매개변수&quot;">​</a></h1><p><em>매개변수</em> 화면은 기체와 관련된 매개변수를 검색하고 수정합니다.</p><div class="tip custom-block"><p class="custom-block-title">Having trouble?</p><p>If parameters fail to download, see <a href="./../troubleshooting/parameter_download.html">Parameter Download Failures</a>.</p></div><div class="info custom-block"><p class="custom-block-title">INFO</p><p>PX4 Pro와 ArduPilot은 매개변수들은 서로 다르지만, 모두 설정가능합니다.</p></div><h2 id="매개변수-검색" tabindex="-1">매개변수 검색 <a class="header-anchor" href="#매개변수-검색" aria-label="Permalink to &quot;매개변수 검색&quot;">​</a></h2><p>매개변수는 그룹화되어 있습니다. Select a group of parameters to view by clicking on the buttons to the left.</p><p><em>검색</em> 필드에 용어를 입력하여 매개변수를 _검색_합니다. 그러면, 입력된 하위 문자열이 포함된 모든 매개변수 이름 및 설명 목록이 표시됩니다(검색을 재설정하려면 <strong>지우기</strong>를 누르십시오).</p><h2 id="changing-a-parameter" tabindex="-1">Changing a Parameter <a class="header-anchor" href="#changing-a-parameter" aria-label="Permalink to &quot;Changing a Parameter&quot;">​</a></h2><p>To change the value of a parameter click on the parameter row in a group or search list. This will open a side dialog in which you can update the value (this dialog also provides additional detailed information about the parameter - including whether a reboot is required for the change to take effect).</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p><strong>저장</strong> 버튼을 클릭하면 매개변수는 기체에 업로드됩니다. 매개변수에 따라 변경된 내용을 적용하기 위해서 비행 컨트롤러 재부팅이 필요할 수 있습니다.</p></div><h2 id="도구" tabindex="-1">도구 <a class="header-anchor" href="#도구" aria-label="Permalink to &quot;도구&quot;">​</a></h2><p>화면의 오른쪽 상단의 <strong>도구</strong> 메뉴에서 추가 옵션을 선택할 수 있습니다.</p><p><strong>새로 고침</strong> <br>모든 매개변수를 기체로부터 재로딩합니다.</p><p><strong>기본값으로 재설정</strong> <br>모든 매개변수를 펌웨어의 기본값으로 재설정합니다.</p><p><strong>파일에서 불러오기 / 파일에 저장</strong> <br>기존 파일에서 매개변수를 불러오거나 현재 매개변수 설정을 파일에 저장합니다.</p><p><strong>RC를 Param으로 지우기</strong> <br>이것은 RC 송신기 제어와 매개변수간의 연관성을 모두 삭제합니다. For more information see: <a href="./../setup_view/radio.html#param-tuning-channels-px4">Radio Setup &gt; Param Tuning Channels</a>.</p><p><strong>기체 재부팅</strong> <br>기체을 재부팅합니다 (일부 매개변수를 변경후에 요구됩니다).</p>',17)]))}const u=e(s,[["render",i]]);export{m as __pageData,u as default};
